-- Prompt 24 expiry, private details, reporting and accepted conversations.
begin;
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
do $$declare request_id uuid;begin request_id:=public.create_partner_request('30000000-0000-4000-8000-000000000001',now()+interval'2 days',now()+interval'2 days 2 hours','bouldering','open','social','Friendly session','Meet by reception at 18:00');perform set_config('test.partner_request',request_id::text,true);end$$;
set local role service_role;insert into public.partner_requests(id,gym_id,profile_id,title,body,status,expires_at)values('98000000-0000-4000-8000-000000000001','30000000-0000-4000-8000-000000000001','10000000-0000-4000-8000-000000000004','Expired','Old','open',now()-interval'1 day');
set local role authenticated;select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);
do $$declare row record;interest_id uuid;begin select*into row from public.get_partner_requests('30000000-0000-4000-8000-000000000001')where id=current_setting('test.partner_request')::uuid;if row.id is null or row.exact_start is not null or row.availability_note is not null then raise exception'Private request details leaked';end if;if exists(select 1 from public.get_partner_requests('30000000-0000-4000-8000-000000000001')where id='98000000-0000-4000-8000-000000000001')then raise exception'Expired request appeared';end if;interest_id:=public.express_partner_interest('30000000-0000-4000-8000-000000000001',row.id,'Happy to join');perform set_config('test.partner_interest',interest_id::text,true);end$$;
select public.report_partner_request('30000000-0000-4000-8000-000000000001',current_setting('test.partner_request')::uuid,'Test report');
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);
select public.respond_partner_interest('30000000-0000-4000-8000-000000000001',current_setting('test.partner_interest')::uuid,true);
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);
do $$declare row record;begin select*into row from public.get_partner_requests('30000000-0000-4000-8000-000000000001')where id=current_setting('test.partner_request')::uuid;if row.exact_start is null or row.availability_note<>'Meet by reception at 18:00'then raise exception'Accepted member did not receive private details';end if;if not exists(select 1 from public.chat_channels channel join public.channel_members member on member.channel_id=channel.id where channel.channel_type='partner'and member.profile_id=auth.uid())then raise exception'Private conversation was not created';end if;end$$;
set local role service_role;do $$begin if not exists(select 1 from public.audit_logs where action='partner_request.reported'and target_id=current_setting('test.partner_request')::uuid)then raise exception'Partner report audit missing';end if;end$$;
rollback;
